-- LIU graduate data seed migration.
-- Idempotent import for the canonical LIU graduate dataset.

ALTER TABLE graduate_program DROP CONSTRAINT IF EXISTS uq_graduate_program_university_url;

DO $$
DECLARE
    v_university_id BIGINT;
BEGIN

    INSERT INTO university (name, name_ar, acronym, country, city, latitude, longitude, campus_name, campus_type)
    SELECT 'Lebanese International University', NULL, 'LIU', 'Lebanon', NULL, NULL, NULL, NULL, NULL
    WHERE NOT EXISTS (SELECT 1 FROM university WHERE name = 'Lebanese International University');

    SELECT id INTO v_university_id FROM university WHERE name = 'Lebanese International University' ORDER BY id LIMIT 1;

    INSERT INTO degree_type (code, name) VALUES
        ('MASTER', 'Master'),
        ('PHD', 'Doctor of Philosophy'),
        ('DIPLOMA', 'Diploma'),
        ('CERTIFICATE', 'Certificate')
    ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, updated_at = NOW();

    INSERT INTO language (name, code, native_name) VALUES
        ('English', 'en', 'English'),
        ('French', 'fr', 'Français'),
        ('Arabic', 'ar', 'العربية'),
        ('Multilingual', 'multi', 'Multilingual')
    ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, native_name = EXCLUDED.native_name;

    CREATE TEMP TABLE liu_source_seed (source_id TEXT PRIMARY KEY, title TEXT NOT NULL, url TEXT NOT NULL, source_type TEXT NOT NULL, accessed_at DATE, notes TEXT) ON COMMIT DROP;
    INSERT INTO liu_source_seed SELECT source_id, page_title, url, source_type, accessed_at, notes FROM jsonb_to_recordset($LIU_SOURCES$[{"source_id":"LIU-SRC-001","page_title":"LIU Main Website / Homepage","url":"https://liu.edu.lb/LIU/","date_accessed":"2026-07-04","source_type":"html","notes":"Primary LIU website navigation; links to admissions, academics, calendar, tuition, schools, and official LIU contact information."},{"source_id":"LIU-SRC-002","page_title":"School of Arts & Sciences - Graduate","url":"https://liu.edu.lb/NewLIU2022/SAS/graduate.php","date_accessed":"2026-07-04","source_type":"html","notes":"Official graduate page listing SAS master admission documents and three graduate programs: MS Computer Science, MS Food Technology, MS Mathematics/Applied Mathematics."},{"source_id":"LIU-SRC-003","page_title":"School of Arts & Sciences - Graduate Of Art & Science","url":"https://liu.edu.lb/SoASchool/view_page_content.php?page_name=R3JhZHVhdGU%3D&template_id=Mg%3D%3D","date_accessed":"2026-07-04","source_type":"html","notes":"Alternate official SAS graduate page with master applicant documents, fees, and master programs."},{"source_id":"LIU-SRC-004","page_title":"Admission Requirements","url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=QWRtaXNzaW9uIFJlcXVpcmVtcw%3D%3D&template_id=Mw%3D%3D","date_accessed":"2026-07-04","source_type":"html","notes":"General admissions page found from official LIU navigation; includes application process language and links to tuition and financial aid."},{"source_id":"LIU-SRC-005","page_title":"Admission Requirements","url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=QWRtaXNzaW9uIFJlcXVpcmVudHM%3D&template_id=Mw%3D%3D","date_accessed":"2026-07-04","source_type":"html","notes":"Official admissions page variant indexed by LIU; used for general admissions process references."},{"source_id":"LIU-SRC-006","page_title":"Tuition Fees","url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D","date_accessed":"2026-07-04","source_type":"html","notes":"Official tuition page with per-credit graduate tuition by school/program, fee items, refund policy, payment locations, and financial aid statement."},{"source_id":"LIU-SRC-007","page_title":"School of Business","url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=U2Nob29sIG9mIEJ1c2luZXNz&template_id=NQ%3D%3D","date_accessed":"2026-07-04","source_type":"html","notes":"Official School of Business overview; states SoBU includes an MBA program with eight different emphases."},{"source_id":"LIU-SRC-008","page_title":"University Catalogue 2022-2023","url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official LIU catalogue PDF. Contains schools, academic rules/regulations, admissions, transfer criteria, and detailed undergraduate/graduate program sections."},{"source_id":"LIU-SRC-009","page_title":"Admission Leaflets","url":"https://admincms.liu.edu.lb/uploads/userPdf/AdmissionLeaflets.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official admission leaflet PDF; search snippet identifies master applicant required documents and application/exam fees, but PDF text extraction was limited."},{"source_id":"LIU-SRC-010","page_title":"Admission and Registration Office - Academic","url":"https://liu.edu.lb/admissionRegistration/view_page_content.php?page_name=QWNhZGVtaWM%3D&template_id=Mg%3D%3D","date_accessed":"2026-07-04","source_type":"html","notes":"Official Admission & Registration page; states LIU offers about 63 programs/majors leading to Bachelor, Master, and Doctoral Degrees (PharmD) and has five schools."},{"source_id":"LIU-SRC-011","page_title":"Academic Calendar","url":"https://liu.edu.lb/LIU/calendar.php","date_accessed":"2026-07-04","source_type":"html","notes":"Official calendar page discovered from LIU navigation; detailed events were not captured in extracted text."},{"source_id":"LIU-SRC-012","page_title":"Research & Graduate Studies - Publications / PhD Partnerships","url":"https://liu.edu.lb/NewLIU2022/ORGS/publications.php","date_accessed":"2026-07-04","source_type":"html","notes":"Official Research & Graduate Studies page; describes LIU faculty co-supervision of PhD students through partner universities, especially in Engineering."},{"source_id":"LIU-SRC-013","page_title":"LIU Factsheet","url":"https://liu.edu.lb/NewLIU2022/OIR/pdf/LIU%20Factsheet.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official factsheet PDF. States five schools, 41 undergraduate majors, 17 graduate majors, programs from Bachelor to Masters to PharmD, and mobility admission documents including English competence certificate."},{"source_id":"LIU-SRC-014","page_title":"Digital Brochure","url":"https://applynow.liu.edu.lb/assets/Digital%20Brochure.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official LIU admissions brochure; includes financial aid conditions and payment plan language: four payments per semester or eight per year."},{"source_id":"LIU-SRC-015","page_title":"Exchange and Visiting Students","url":"https://liu.edu.lb/NewLIU2022/OIR/pdf/FOR%20EXCHANGE%20AND%20VISITING%20STUDENTS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official international/exchange students PDF; covers Erasmus+ credit mobility for students and doctoral candidates."},{"source_id":"LIU-SRC-016","page_title":"Exchange Guide","url":"https://liu.edu.lb/NewLIU2022/OIR/pdf/Exchange%20Guide.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official exchange guide PDF; describes international agreements and that LIU organizes Masters and PhD research programs."},{"source_id":"LIU-SRC-017","page_title":"MBA Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/MBA-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for Master of Business Administration in General Business Administration, graduate level, 39 credits."},{"source_id":"LIU-SRC-018","page_title":"WMBA Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/WMBA-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for Master of Business Administration LIU-Hochschule Worms dual degree, graduate level, 56 credits."},{"source_id":"LIU-SRC-019","page_title":"MS Electrical Engineering Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/MEENG-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for MS Electrical Engineering, graduate level, 52 credits."},{"source_id":"LIU-SRC-020","page_title":"MS Mechanical Engineering Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/MMENG-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for MS Mechanical Engineering, graduate level, 52 credits."},{"source_id":"LIU-SRC-021","page_title":"MS Industrial Engineering Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/MIENG-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for MS Industrial Engineering, graduate level."},{"source_id":"LIU-SRC-022","page_title":"MS Surveying Engineering Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/MSURV-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for MS Surveying Engineering, graduate level."},{"source_id":"LIU-SRC-023","page_title":"MS Computer & Communication Engineering Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/MCCE-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for MS Computer & Communication Engineering, graduate level."},{"source_id":"LIU-SRC-024","page_title":"Masters of Education in Educational Management Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/ELMM-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for Masters of Education in Educational Management, graduate level, 39 credits."},{"source_id":"LIU-SRC-025","page_title":"Masters of Education in Teaching English as a Second Language Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/EDUM-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for Masters of Education in Teaching English as a Second Language, graduate level, 39 credits."},{"source_id":"LIU-SRC-026","page_title":"PharmD Plan of Study","url":"https://liu.edu.lb/NewLIU2022/metaData/PHRD-POS.pdf","date_accessed":"2026-07-04","source_type":"pdf","notes":"Official metadata PDF for Doctor of Pharmacy / PharmD; discovered because official pages describe Doctoral Degrees as PharmD. Out of scope for MASTER/PHD seeding unless PharmD is later explicitly included."}]$LIU_SOURCES$::jsonb) AS x(source_id TEXT, page_title TEXT, url TEXT, source_type TEXT, accessed_at DATE, notes TEXT);
    INSERT INTO source (university_id, title, url, source_type, accessed_at) SELECT v_university_id, title, url, source_type, accessed_at FROM liu_source_seed ON CONFLICT (university_id, url) DO UPDATE SET title = EXCLUDED.title, source_type = EXCLUDED.source_type, accessed_at = EXCLUDED.accessed_at, updated_at = NOW();

    CREATE TEMP TABLE liu_faculty_seed (name TEXT PRIMARY KEY, short_name TEXT, faculty_type TEXT NOT NULL, official_url TEXT, notes TEXT) ON COMMIT DROP;
    INSERT INTO liu_faculty_seed SELECT name, short_name, faculty_type, official_url, notes FROM jsonb_to_recordset($LIU_FACULTIES$[{"name":"School of Business","short_name":null,"faculty_type":"SCHOOL","official_url":null,"notes":"Imported from LIU graduate program data."},{"name":"School of Engineering","short_name":null,"faculty_type":"SCHOOL","official_url":null,"notes":"Imported from LIU graduate program data."},{"name":"School of Arts and Sciences","short_name":null,"faculty_type":"SCHOOL","official_url":null,"notes":"Imported from LIU graduate program data."},{"name":"School of Education","short_name":null,"faculty_type":"SCHOOL","official_url":null,"notes":"Imported from LIU graduate program data."}]$LIU_FACULTIES$::jsonb) AS x(name TEXT, short_name TEXT, faculty_type TEXT, official_url TEXT, notes TEXT);
    INSERT INTO university_faculty (university_id, name, short_name, faculty_type, official_url, notes) SELECT v_university_id, name, short_name, faculty_type, official_url, notes FROM liu_faculty_seed ON CONFLICT (university_id, name) DO UPDATE SET short_name = EXCLUDED.short_name, faculty_type = EXCLUDED.faculty_type, official_url = EXCLUDED.official_url, notes = EXCLUDED.notes, updated_at = NOW();

    CREATE TEMP TABLE liu_program_seed (program_key TEXT PRIMARY KEY, faculty_name TEXT NOT NULL, major_category TEXT, major TEXT, degree_type TEXT NOT NULL, official_degree_name TEXT, thesis_or_non_thesis TEXT, credits INTEGER, duration_value NUMERIC(10, 2), duration_unit TEXT, primary_language_code TEXT, delivery_mode TEXT, program_description TEXT, official_program_url TEXT, source_url TEXT NOT NULL, notes TEXT) ON COMMIT DROP;
    INSERT INTO liu_program_seed SELECT program_key, faculty_name, major_category, major, degree_type, official_degree_name, thesis_or_non_thesis, credits, duration_value, duration_unit, primary_language_code, delivery_mode, program_description, official_program_url, source_url, notes FROM jsonb_to_recordset($LIU_PROGRAMS$[{"program_key":"liu-sobu-mba","faculty_name":"School of Business","major_category":"Business Administration","major":"General Management","degree_type":"MASTER","official_degree_name":"Master of Business Administration (MBA)","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/MBA-POS.pdf","source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=U2Nob29sIG9mIEJ1c2luZXNz&template_id=NQ%3D%3D","notes":"Official School of Business page says the MBA has multiple emphases. Those emphases are kept as concentrations under this single MBA record rather than split into separate programs.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-sobu-mbat","faculty_name":"School of Business","major_category":"Business Administration","major":"General Management","degree_type":"MASTER","official_degree_name":"Master of Business Administration with Thesis (MBAT)","thesis_or_non_thesis":"THESIS","credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=U2Nob29sIG9mIEJ1c2luZXNz&template_id=NQ%3D%3D","notes":"Distinct title listed in the official catalogue. No separate plan-of-study PDF was identified in the discovery package, so the catalogue is used as the canonical official URL.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-sobu-wmba","faculty_name":"School of Business","major_category":"Business Administration","major":"WORMS / LIU-Hochschule Worms MBA dual degree","degree_type":"MASTER","official_degree_name":"WORMS / LIU-Hochschule Worms MBA dual degree","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/WMBA-POS.pdf","source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=U2Nob29sIG9mIEJ1c2luZXNz&template_id=NQ%3D%3D","notes":"Official dual-degree MBA title surfaced in the catalogue and dedicated WMBA plan-of-study PDF.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soe-ms-computer-communications-engineering","faculty_name":"School of Engineering","major_category":"Engineering","major":"Computer and Communications Engineering","degree_type":"MASTER","official_degree_name":"MS in Computer and Communications Engineering","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/MCCE-POS.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"Official metadata PDF exists for this engineering master.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soe-ms-electrical-engineering","faculty_name":"School of Engineering","major_category":"Engineering","major":"Electrical Engineering","degree_type":"MASTER","official_degree_name":"MS in Electrical Engineering","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/MEENG-POS.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"Official metadata PDF exists for this engineering master.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soe-ms-electronics-engineering","faculty_name":"School of Engineering","major_category":"Engineering","major":"Electronics Engineering","degree_type":"MASTER","official_degree_name":"MS in Electronics Engineering","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"Listed in the official catalogue. No separate metadata PDF was found in the discovery package.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soe-ms-electronics-engineering-biomedical-emphasis","faculty_name":"School of Engineering","major_category":"Engineering","major":"Electronics Engineering, emphasis on Biomedical Engineering","degree_type":"MASTER","official_degree_name":"MS in Electronics Engineering, emphasis on Biomedical Engineering","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"The official catalogue explicitly names the biomedical emphasis. It is retained as a separate row because the title is published that way, but the catalogue is the only stable source URL discovered for it.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soe-ms-industrial-engineering","faculty_name":"School of Engineering","major_category":"Engineering","major":"Industrial Engineering","degree_type":"MASTER","official_degree_name":"MS in Industrial Engineering","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/MIENG-POS.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"Official metadata PDF exists for this engineering master.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soe-ms-mechanical-engineering","faculty_name":"School of Engineering","major_category":"Engineering","major":"Mechanical Engineering","degree_type":"MASTER","official_degree_name":"MS in Mechanical Engineering","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/MMENG-POS.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"Official metadata PDF exists for this engineering master.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soe-ms-surveying-engineering","faculty_name":"School of Engineering","major_category":"Engineering","major":"Surveying Engineering","degree_type":"MASTER","official_degree_name":"MS in Surveying Engineering","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/MSURV-POS.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"Official metadata PDF exists for this engineering master.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soas-ms-computer-science","faculty_name":"School of Arts and Sciences","major_category":"Arts and Sciences","major":"Computer Science","degree_type":"MASTER","official_degree_name":"Master of Science in Computer Science","thesis_or_non_thesis":null,"credits":36,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/SAS/graduate.php","source_url":"https://liu.edu.lb/NewLIU2022/SAS/graduate.php","notes":"Listed on both SAS graduate pages; treated as one master record.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soas-ms-food-technology","faculty_name":"School of Arts and Sciences","major_category":"Arts and Sciences","major":"Food Technology","degree_type":"MASTER","official_degree_name":"Master of Science in Food Technology","thesis_or_non_thesis":null,"credits":36,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/SoASchool/view_page_content.php?page_name=R3JhZHVhdGU%3D&template_id=Mg%3D%3D","source_url":"https://liu.edu.lb/NewLIU2022/SAS/graduate.php","notes":"Listed on both SAS graduate pages; treated as one master record.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soas-ms-mathematics-applied-mathematics","faculty_name":"School of Arts and Sciences","major_category":"Arts and Sciences","major":"Mathematics / Applied Mathematics","degree_type":"MASTER","official_degree_name":"Master of Science in Mathematics / Applied Mathematics","thesis_or_non_thesis":null,"credits":36,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","source_url":"https://liu.edu.lb/NewLIU2022/SAS/graduate.php","notes":"The official graduate pages use dual naming (Mathematics / Applied Mathematics). The catalogue is used as the stable canonical URL because the official pages were ambiguous in the discovery set.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soedu-med-educational-management","faculty_name":"School of Education","major_category":"Education","major":"Educational Management","degree_type":"MASTER","official_degree_name":"Masters of Education in Educational Management","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/ELMM-POS.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"Official metadata PDF exists for this education master.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"},{"program_key":"liu-soedu-med-teaching-english-second-language","faculty_name":"School of Education","major_category":"Education","major":"Teaching English as a Second Language","degree_type":"MASTER","official_degree_name":"Masters of Education in Teaching English as a Second Language","thesis_or_non_thesis":null,"credits":null,"duration_value":null,"duration_unit":null,"primary_language_code":null,"delivery_mode":null,"program_description":null,"official_program_url":"https://liu.edu.lb/NewLIU2022/metaData/EDUM-POS.pdf","source_url":"https://syslb.liu.edu.lb/syslbdatadir/Documents/09_University_Catalog.pdf","notes":"Official metadata PDF exists for this education master.","tuition_source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=VHVpdGlvbiBGZWVz&template_id=Mw%3D%3D"}]$LIU_PROGRAMS$::jsonb) AS x(program_key TEXT, faculty_name TEXT, major_category TEXT, major TEXT, degree_type TEXT, official_degree_name TEXT, thesis_or_non_thesis TEXT, credits INTEGER, duration_value NUMERIC(10, 2), duration_unit TEXT, primary_language_code TEXT, delivery_mode TEXT, program_description TEXT, official_program_url TEXT, source_url TEXT, notes TEXT);
    INSERT INTO graduate_program (university_id, faculty_id, department_id, degree_type_id, program_key, major_category, major, official_degree_name, thesis_or_non_thesis, credits, duration_value, duration_unit, primary_language_id, delivery_mode, program_description, official_program_url, source_id, notes)
    SELECT v_university_id, f.id, NULL, dt.id, p.program_key, p.major_category, p.major, p.official_degree_name, p.thesis_or_non_thesis, p.credits, p.duration_value, p.duration_unit, NULL, p.delivery_mode, p.program_description, p.official_program_url, s.id, p.notes
    FROM liu_program_seed p
    JOIN university_faculty f ON f.university_id = v_university_id AND f.name = p.faculty_name
    JOIN degree_type dt ON dt.code = p.degree_type
    JOIN source s ON s.university_id = v_university_id AND s.url = p.source_url
