    INSERT INTO liu_admission_seed SELECT record_key, scope_level, requirement_type, requirement_text, comparison_operator, threshold_value, threshold_unit, is_required, notes, source_url, faculty_name, program_key FROM jsonb_to_recordset($LIU_ADMISSIONS$[{"record_key":"liu-adm-general-graduate","scope_level":"UNIVERSITY","requirement_type":"GENERAL","requirement_text":"Graduate applicants apply through the admissions flow, submit the required file, and complete any school- or program-specific steps such as entrance tests or additional review where published.","comparison_operator":null,"threshold_value":null,"threshold_unit":null,"is_required":true,"notes":null,"source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=QWRtaXNzaW9uIFJlcXVpcmVtcw%3D%3D&template_id=Mw%3D%3D","faculty_name":null,"program_key":null},{"record_key":"liu-adm-mba-general-management","scope_level":"PROGRAM","requirement_type":"GENERAL","requirement_text":"Bachelor's degree from a recognized university; MBA entrance exam required unless the applicant has a GMAT score above 500; letter of intent, two recommendation letters, CV, and certified bachelor's transcripts.","comparison_operator":null,"threshold_value":null,"threshold_unit":null,"is_required":true,"notes":null,"source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=U2Nob29sIG9mIEJ1c2luZXNz&template_id=NQ%3D%3D","faculty_name":"School of Business","program_key":"liu-sobu-mba"},{"record_key":"liu-adm-mba-gmat","scope_level":"PROGRAM","requirement_type":"GMAT","requirement_text":"GMAT score above 500 exempts the applicant from the MBA entrance exam.","comparison_operator":">","threshold_value":500,"threshold_unit":"SCORE","is_required":true,"notes":null,"source_url":"https://liu.edu.lb/LIU/view_page_content.php?page_name=U2Nob29sIG9mIEJ1c2luZXNz&template_id=NQ%3D%3D","faculty_name":"School of Business","program_key":"liu-sobu-mba"}]$LIU_ADMISSIONS$::jsonb) AS x(record_key TEXT, scope_level TEXT, requirement_type TEXT, requirement_text TEXT, comparison_operator TEXT, threshold_value NUMERIC(12, 2), threshold_unit TEXT, is_required BOOLEAN, notes TEXT, source_url TEXT, faculty_name TEXT, program_key TEXT);
    INSERT INTO graduate_admission_requirement (university_id, faculty_id, department_id, program_id, scope_level, record_key, requirement_type, requirement_text, comparison_operator, threshold_value, threshold_unit, is_required, notes, source_id)
    SELECT v_university_id, CASE WHEN a.faculty_name IS NULL THEN NULL ELSE f.id END, NULL, CASE WHEN a.program_key IS NULL THEN NULL ELSE gp.id END, a.scope_level, a.record_key, a.requirement_type, a.requirement_text, a.comparison_operator, a.threshold_value, a.threshold_unit, a.is_required, a.notes, s.id
    FROM liu_admission_seed a
    LEFT JOIN university_faculty f ON f.university_id = v_university_id AND f.name = a.faculty_name
    LEFT JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = a.program_key
    JOIN source s ON s.university_id = v_university_id AND s.url = a.source_url
    ON CONFLICT (university_id, record_key) DO UPDATE SET faculty_id = EXCLUDED.faculty_id, department_id = EXCLUDED.department_id, program_id = EXCLUDED.program_id, scope_level = EXCLUDED.scope_level, requirement_type = EXCLUDED.requirement_type, requirement_text = EXCLUDED.requirement_text, comparison_operator = EXCLUDED.comparison_operator, threshold_value = EXCLUDED.threshold_value, threshold_unit = EXCLUDED.threshold_unit, is_required = EXCLUDED.is_required, notes = EXCLUDED.notes, source_id = EXCLUDED.source_id, updated_at = NOW();

