    INSERT INTO graduate_program_source (university_id, program_id, source_id, source_role, source_order, evidence_text, notes)
    SELECT v_university_id, gp.id, s.id, ps.source_role, ps.source_order, ps.evidence_text, ps.notes
    FROM liu_program_source_seed ps
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = ps.program_key
    JOIN source s ON s.university_id = v_university_id AND s.url = ps.source_url
    ON CONFLICT (program_id, source_id, source_role) DO UPDATE SET source_order = EXCLUDED.source_order, evidence_text = EXCLUDED.evidence_text, notes = EXCLUDED.notes, updated_at = NOW();

END $$;
